package rate

import (
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/billing/rating"
	"github.com/openmeterio/openmeter/openmeter/productcatalog"
)

type Unit struct{ ProgressiveBillingMeteredPricer }

var _ Pricer = (*Unit)(nil)

func (p Unit) GenerateDetailedLines(l PricerCalculateInput) (rating.DetailedLines, error) {
	unitPrice, err := l.GetPrice().AsUnit()
	if err != nil {
		return nil, fmt.Errorf("converting price to unit price: %w", err)
	}
	usage, err := l.GetUsage()
	if err != nil {
		return nil, err
	}
	if usage.Quantity.IsPositive() {
		return rating.DetailedLines{{
			Name:                   fmt.Sprintf("%s: usage in period", l.GetName()),
			Quantity:               usage.Quantity,
			PerUnitAmount:          unitPrice.Amount,
			ChildUniqueReferenceID: rating.UnitPriceUsageChildUniqueReferenceID,
			PaymentTerm:            productcatalog.InArrearsPaymentTerm,
		}}, nil
	}
	return nil, nil
}

package mutator

import (
	"fmt"

	"github.com/alpacahq/alpacadecimal"

	"github.com/openmeterio/openmeter/openmeter/billing/models/stddetailedline"
	"github.com/openmeterio/openmeter/openmeter/billing/rating"
	"github.com/openmeterio/openmeter/openmeter/billing/rating/service/rate"
	"github.com/openmeterio/openmeter/openmeter/productcatalog"
)

type MinAmountCommitment struct{}

var _ PostCalculationMutator = (*MinAmountCommitment)(nil)

func (m *MinAmountCommitment) Mutate(i rate.PricerCalculateInput, pricerResult rating.DetailedLines) (rating.DetailedLines, error) {
	c := i.GetPrice().GetCommitments()
	if c.MinimumAmount == nil || !i.IsLastInPeriod() {
		return pricerResult, nil
	}
	prev, err := i.GetPreviouslyBilledAmount()
	if err != nil {
		return pricerResult, err
	}
	total := pricerResult.Sum(i.CurrencyCalculator).Add(prev)
	if total.LessThan(*c.MinimumAmount) {
		period := i.GetServicePeriod()
		if i.IsProgressivelyBilled() {
			period = i.FullProgressivelyBilledServicePeriod
		}
		pricerResult = append(pricerResult, rating.DetailedLine{
			Name:                   fmt.Sprintf("%s: minimum spend", i.GetName()),
			Quantity:               alpacadecimal.NewFromFloat(1),
			PerUnitAmount:          i.CurrencyCalculator.RoundToPrecision(c.MinimumAmount.Sub(total)),
			ChildUniqueReferenceID: rating.MinSpendChildUniqueReferenceID,
			PaymentTerm:            productcatalog.InArrearsPaymentTerm,
			Category:               stddetailedline.CategoryCommitment,
			Period:                 &period,
		})
	}
	return pricerResult, nil
}
